const payload = ($json && $json.body) ? $json.body : ($json || {});
const token = payload.yandex_oauth_token || $env.YANDEX_OAUTH_TOKEN || $env.YANDEX_TOKEN || 'y0__xCIj9GiBxjMqD8gnNLv6xYi53tNIuy00fSsAXVvz3ME1dx2Lg';
const clientLogin = payload.client_login || 'siberian.gruzoviki';
const counterId = payload.metrika_counter_id || '105289797';
const periodLabel = payload.period_label || 'yesterday';
let dateFrom = payload.date_from || null, dateTo = payload.date_to || null;
if (!dateFrom || !dateTo) {
  const now = new Date(), today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const fmt = (d) => d.toISOString().slice(0, 10);
  const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
  switch (periodLabel) {
    case 'today': dateFrom = fmt(today); dateTo = fmt(today); break;
    case 'yesterday': dateFrom = fmt(yesterday); dateTo = fmt(yesterday); break;
    case 'last_7_days': { const d = new Date(today); d.setDate(today.getDate() - 7); dateFrom = fmt(d); dateTo = fmt(yesterday); break; }
    case 'last_30_days': { const d = new Date(today); d.setDate(today.getDate() - 30); dateFrom = fmt(d); dateTo = fmt(yesterday); break; }
    case 'this_month': { const first = new Date(today.getFullYear(), today.getMonth(), 1); dateFrom = fmt(first); dateTo = fmt(today); break; }
    default: dateFrom = fmt(yesterday); dateTo = fmt(yesterday);
  }
}
return [{ json: { yandex_oauth_token: token, client_login: clientLogin, metrika_counter_id: counterId, period_label: periodLabel, date_from: dateFrom, date_to: dateTo } }];

const rawData = $input.first().json.data || [];
const formattedData = rawData.map(row => ({
  event_name: row.dimensions[0].name || 'Неизвестное событие',
  unique_devices: row.metrics[0] || 0,
  total_events: row.metrics[1] || 0
}));
return formattedData.map(item => ({ json: item }));

const setInputs = $('Set Inputs + Resolve Dates').first().json;
const dateFrom = setInputs.date_from;
const dateTo = setInputs.date_to;
const token = $env.APPMETRICA_TOKEN || 'y0__xCIj9GiBxi1vz8gk8e18BYV3hcGH9BGMLJrW38Yqfst56Q4fA';
const auth = { Authorization: 'OAuth ' + token };
const NEW_APP_ID = '6273311';
const OLD_APP_ID = '4735402';

const OVERLAP_START = '2026-03-27';
const OVERLAP_END = '2026-03-31';

const parseIso = (s) => {
  const [y, m, d] = String(s).split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d));
};
const fmtIso = (d) => {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};
const maxDate = (a, b) => (a > b ? a : b);
const minDate = (a, b) => (a < b ? a : b);

const reqFrom = parseIso(dateFrom);
const reqTo = parseIso(dateTo);
const overlapFrom = maxDate(reqFrom, parseIso(OVERLAP_START));
const overlapTo = minDate(reqTo, parseIso(OVERLAP_END));
const hasOldRange = overlapFrom <= overlapTo;

const ranges = [
  { appId: NEW_APP_ID, from: dateFrom, to: dateTo },
];
if (hasOldRange) {
  ranges.push({ appId: OLD_APP_ID, from: fmtIso(overlapFrom), to: fmtIso(overlapTo) });
}

async function fetchJson(url) {
  const r = await fetch(url, { headers: auth });
  if (!r.ok) throw new Error(`HTTP ${r.status}`);
  return r.json();
}

const eventsByName = new Map();
const geoByCity = new Map();
const hourByHour = new Map();
let installsTotal = 0;
const sourcesByName = new Map();

for (const rg of ranges) {
  try {
    const eventsUrl = 'https://api.appmetrica.yandex.ru/stat/v1/data?id=' + rg.appId
      + '&metrics=ym:ce2:devicesWithEvent,ym:ce2:allEvents'
      + '&dimensions=ym:ce2:eventLabel'
      + '&date1=' + rg.from + '&date2=' + rg.to
      + '&sort=-ym:ce2:allEvents&limit=100&accuracy=medium';
    const eventsResp = await fetchJson(eventsUrl);
    for (const row of (eventsResp.data || [])) {
      const name = ((row.dimensions || [])[0] || {}).name || 'Неизвестное событие';
      const cur = eventsByName.get(name) || { event_name: name, unique_devices: 0, total_events: 0 };
      cur.unique_devices += Math.round((row.metrics || [])[0] || 0);
      cur.total_events += Math.round((row.metrics || [])[1] || 0);
      eventsByName.set(name, cur);
    }
  } catch (e) {}

  try {
    const geoUrl = 'https://api.appmetrica.yandex.ru/stat/v1/data?id=' + rg.appId
      + '&metrics=ym:ce2:devicesWithEvent&dimensions=ym:ce2:regionCity'
      + '&date1=' + rg.from + '&date2=' + rg.to
      + '&sort=-ym:ce2:devicesWithEvent&limit=100&accuracy=medium';
    const geoResp = await fetchJson(geoUrl);
    for (const row of (geoResp.data || [])) {
      const city = ((row.dimensions || [])[0] || {}).name || '';
      if (!city || city === 'Unknown') continue;
      const prev = geoByCity.get(city) || 0;
      geoByCity.set(city, prev + Math.round((row.metrics || [])[0] || 0));
    }
  } catch (e) {}

  try {
    const bytimeUrl = 'https://api.appmetrica.yandex.ru/stat/v1/data/bytime?id=' + rg.appId
      + '&metrics=ym:ce2:allEvents&group=Hour'
      + '&date1=' + rg.from + '&date2=' + rg.to
      + '&accuracy=medium';
    const bytimeResp = await fetchJson(bytimeUrl);
    if (Array.isArray(bytimeResp.time_intervals) && bytimeResp.data && bytimeResp.data[0]) {
      const vals = (bytimeResp.data[0].metrics || [])[0] || [];
      bytimeResp.time_intervals.forEach((t, i) => {
        const ts = Array.isArray(t) ? t[0] : t;
        const h = new Date(ts * 1000).getUTCHours();
        const prev = hourByHour.get(h) || 0;
        hourByHour.set(h, prev + Math.round(Array.isArray(vals) ? (vals[i] || 0) : 0));
      });
    }
  } catch (e) {}

  try {
    const installsUrl = 'https://api.appmetrica.yandex.ru/stat/v1/data?id=' + rg.appId
      + '&metrics=ym:ad:installs&dimensions=ym:ad:publisherName'
      + '&date1=' + rg.from + '&date2=' + rg.to
      + '&sort=-ym:ad:installs&limit=100&accuracy=medium';
    const installsResp = await fetchJson(installsUrl);
    for (const row of (installsResp.data || [])) {
      const src = ((row.dimensions || [])[0] || {}).name || 'Unknown';
      const cnt = Math.round((row.metrics || [])[0] || 0);
      installsTotal += cnt;
      sourcesByName.set(src, (sourcesByName.get(src) || 0) + cnt);
    }
  } catch (e) {}
}

const events = Array.from(eventsByName.values()).sort((a, b) => b.total_events - a.total_events);
const geo = Array.from(geoByCity.entries())
  .map(([city, drivers]) => ({ city, drivers }))
  .sort((a, b) => b.drivers - a.drivers)
  .slice(0, 8);
const hours = Array.from(hourByHour.entries())
  .map(([hour, events]) => ({ hour: Number(hour), events }))
  .sort((a, b) => a.hour - b.hour);
const sources = Array.from(sourcesByName.entries())
  .map(([name, installs]) => ({ name, installs }))
  .sort((a, b) => b.installs - a.installs);

return [{
  json: {
    events,
    geo,
    hours,
    installs_total: installsTotal,
    sources
  }
}];

const body = ($json && $json.body) ? $json.body : $json;
const data = Array.isArray(body.data) ? body.data : [];
const dateFrom = body.date_from || '';
const dateTo = body.date_to || '';
const period = body.period_label || '';
const periodNames = { yesterday: 'вчера', last_7_days: 'последние 7 дней', last_30_days: 'последние 30 дней', this_month: 'текущий месяц' };

const formatRuDate = (iso) => {
  if (!iso || typeof iso !== 'string') return iso || '';
  const p = iso.split('-');
  if (p.length !== 3) return iso;
  const d = new Date(Date.UTC(Number(p[0]), Number(p[1]) - 1, Number(p[2])));
  const months = ['янв','фев','мар','апр','май','июн','июл','авг','сен','окт','ноя','дек'];
  return d.getUTCDate() + ' ' + months[d.getUTCMonth()];
};

const rangeFromDates = (dateFrom && dateTo)
  ? (dateFrom === dateTo ? formatRuDate(dateFrom) : (formatRuDate(dateFrom) + ' — ' + formatRuDate(dateTo)))
  : '';
const periodName = rangeFromDates || periodNames[period] || period || 'выбранный период';
const reportTitle = 'Отчёт по ГРУЗАП за период ' + periodName;

const find = (name) => data.find(d => d.event_name === name) || { unique_devices: 0, total_events: 0 };
const activeDrivers = Math.max(...data.map(d => d.unique_devices || 0), 1);
const filterOpen = find('Открыл фильтр').unique_devices;
const zayvki = find('Открыл заявку').unique_devices;
const tel = find('Нажал на телефон в заявке').unique_devices;
const conv = zayvki > 0 ? Math.round(tel / zayvki * 100) : 0;
const reg = find('Зарегистрировался').unique_devices;
const inter = find('Использовал фильтр межгород').total_events;
const city = find('Использовал фильтр по городу').total_events;
const totalRoutes = inter + city;
const interPct = totalRoutes > 0 ? Math.round(inter / totalRoutes * 100) : 0;
const completed = find('Отметил выполненной заявку').unique_devices;

const token = $env.APPMETRICA_TOKEN || 'y0__xCIj9GiBxi1vz8gk8e18BYV3hcGH9BGMLJrW38Yqfst56Q4fA';
const auth = { Authorization: 'OAuth ' + token };
const NEW_APP_ID = '6273311';
const OLD_APP_ID = '4735402';
const OVERLAP_START = '2026-03-27';
const OVERLAP_END = '2026-03-31';

const parseIso = (s) => {
  const [y, m, d] = String(s).split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d));
};
const fmtIso = (d) => {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};
const maxDate = (a, b) => (a > b ? a : b);
const minDate = (a, b) => (a < b ? a : b);

let installsTotal = Number(body.installs_total || 0);
const sourcesByName = new Map();
(Array.isArray(body.sources) ? body.sources : []).forEach((row) => {
  const name = row && row.name ? row.name : 'Unknown';
  const installs = Math.round((row && row.installs) || 0);
  if (installs > 0) sourcesByName.set(name, (sourcesByName.get(name) || 0) + installs);
});

async function fetchJson(url) {
  const r = await fetch(url, { headers: auth });
  if (!r.ok) throw new Error(`HTTP ${r.status}`);
  return r.json();
}

if (!installsTotal && dateFrom && dateTo) {
  const reqFrom = parseIso(dateFrom);
  const reqTo = parseIso(dateTo);
  const overlapFrom = maxDate(reqFrom, parseIso(OVERLAP_START));
  const overlapTo = minDate(reqTo, parseIso(OVERLAP_END));
  const hasOldRange = overlapFrom <= overlapTo;
  const ranges = [{ appId: NEW_APP_ID, from: dateFrom, to: dateTo }];
  if (hasOldRange) ranges.push({ appId: OLD_APP_ID, from: fmtIso(overlapFrom), to: fmtIso(overlapTo) });

  for (const rg of ranges) {
    try {
      const installsUrl = 'https://api.appmetrica.yandex.ru/stat/v1/data?id=' + rg.appId
        + '&metrics=ym:ad:installs&dimensions=ym:ad:publisherName'
        + '&date1=' + rg.from + '&date2=' + rg.to
        + '&sort=-ym:ad:installs&limit=100&accuracy=medium';
      const installsResp = await fetchJson(installsUrl);
      for (const row of (installsResp.data || [])) {
        const src = ((row.dimensions || [])[0] || {}).name || 'Unknown';
        const cnt = Math.round((row.metrics || [])[0] || 0);
        installsTotal += cnt;
        if (cnt > 0) sourcesByName.set(src, (sourcesByName.get(src) || 0) + cnt);
      }
    } catch (e) {}
  }
}

const sources = Array.from(sourcesByName.entries())
  .map(([name, installs]) => ({ name, installs }))
  .sort((a, b) => b.installs - a.installs);
const topSourcesText = sources.length
  ? sources.slice(0, 3).map((item) => item.name + ' — ' + item.installs).join('; ')
  : 'нет данных';

const good = [];
const risks = [];

good.push('Активных водителей: ' + activeDrivers + '.');
if (reg > 0) good.push('Новых регистраций: ' + reg + '.');
if (installsTotal > 0) good.push('Установок за период: ' + installsTotal + '.');
if (topSourcesText !== 'нет данных') good.push('Основные источники установок: ' + topSourcesText + '.');
if (filterOpen > 0) good.push('Открыли фильтр: ' + filterOpen + ' водителей.');
if (zayvki > 0) good.push('Просматривали заявки: ' + zayvki + ' водителей.');
if (totalRoutes > 0) good.push('Маршруты: ' + interPct + '% межгород, ' + (100 - interPct) + '% городские перевозки.');

if (zayvki > 0) risks.push('До звонка доходят ' + tel + ' из ' + zayvki + ' водителей, конверсия ' + conv + '%.');
if (completed > 0) risks.push('Отметили выполненной заявку: ' + completed + ' водителей.');
if (!installsTotal) risks.push('По установкам нет данных в ответе аналитики.');
if (!sources.length) risks.push('По источникам установок нет данных в ответе аналитики.');

const goodLines = good.length ? good.slice(0, 4) : ['Нет достаточного объёма данных для позитивных выводов.'];
const riskLines = risks.length ? risks.slice(0, 4) : ['Явных проблем по доступным метрикам не видно.'];

const text = [
  reportTitle,
  '',
  'Что хорошо:',
  ...goodLines.map((line) => '- ' + line),
  '',
  'Что вызывает беспокойство:',
  ...riskLines.map((line) => '- ' + line)
].join('\n');

return [{ json: { text, period_name: periodName, installs_total: installsTotal, sources } }];

const periodName = $('Подготовить промпт').first().json.period_name || 'выбранный период';
const title = 'Отчёт по ГРУЗАП за период ' + periodName;
const raw = String($json.text || $json.output || $json.response || '');
const lines = raw.split(/\r?\n/);
while (lines.length && !String(lines[0]).trim()) lines.shift();
if (lines.length) lines.shift();
const body = lines.join('\n').trim();
return [{ json: { text: body ? (title + '\n\n' + body) : title } }];
